import React, { useState } from 'react';
import { useApp } from '../../App';
import { Sidebar } from '../../components/Sidebar';
import LiveMap from '../../components/LiveMap';

export default function CleanerPortal() {
  const { complaints, updateComplaint } = useApp();
  const [selected, setSelected] = useState(null);
  const [proofUrl, setProofUrl] = useState('');

  // Sahi lifecycle logic: Cleaner ko wahi tasks dikhane hain jo usko assign huye hain
  // Jab tak Vendor check karke COMPLETED nahi kar deta, tab tak task active rahega.
  const activeTasks = complaints.filter(c => 
    ['ASSIGNED_TO_CLEANER', 'CLEANED_BY_FORCE'].includes(c.status)
  );

  const handleSendProofToVendor = (taskId) => {
    if (!proofUrl.trim()) {
      return alert("Please enter or paste the valid clean site photo URL.");
    }

    // Task ko complete mark karke Vendor verification panel me bhejna
    updateComplaint(taskId, {
      status: 'CLEANED_BY_FORCE',
      cleanerStatus: 'DONE',
      cleanerPhoto: proofUrl.trim()
    });

    alert("Task status updated! Cleanup photo sent to Vendor for verification.");
    setProofUrl('');
    setSelected(null);
  };

  return (
    <div style={{ display: 'flex', height: '100vh', background: '#F7F9FC', overflow: 'hidden', fontFamily: 'system-ui, sans-serif' }}>
      
      {/* Dynamic Field Force Control Sidebar */}
      <Sidebar 
        title="Field Force Ledger" 
        subtitle="Nagpur Ground Operators" 
        navItems={[{ key: 'JOBS', label: 'My Assigned Sweeps', icon: '🧹', count: activeTasks.length }]} 
        activeTab="JOBS" 
        onTabChange={() => {}} 
      />

      <div style={{ flex: 1, display: 'flex', padding: 20, gap: 16, overflow: 'hidden' }}>
        
        {/* LEFT COLUMN: LIST OF ASSIGNED TASKS */}
        <div style={{ flex: 1, overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: 10 }}>
          <h3 style={{ fontSize: 16, color: '#0A1628', margin: '0 0 4px 0' }}>📋 Assigned Work Orders</h3>
          {activeTasks.length === 0 ? (
            <div style={{ background: '#fff', padding: 24, borderRadius: 12, border: '1px solid #DDE3E9', textAlign: 'center', color: '#7A8FA6', fontSize: 13 }}>
              Sab Saaf Hai! No pending tasks assigned to you right now.
            </div>
          ) : (
            activeTasks.map(t => {
              const isPendingVendor = t.status === 'CLEANED_BY_FORCE';
              return (
                <div 
                  key={t.id} 
                  onClick={() => setSelected(t)} 
                  style={{ 
                    background: isPendingVendor ? '#FFF9E6' : '#fff', 
                    padding: 14, 
                    borderRadius: 12, 
                    border: `1px solid ${selected?.id === t.id ? '#1565C0' : isPendingVendor ? '#FFE0B2' : '#DDE3E9'}`, 
                    cursor: 'pointer',
                    boxShadow: '0 2px 4px rgba(0,0,0,0.02)',
                    transition: 'all 0.2s'
                  }}
                >
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <div style={{ fontWeight: 700, fontSize: 14, color: '#0A1628' }}>
                      📍 {t.area || 'Assigned Track Location'}
                    </div>
                    {isPendingVendor && (
                      <span style={{ background: '#E65100', color: '#fff', fontSize: 10, padding: '2px 6px', borderRadius: 4, fontWeight: 700 }}>
                        Awaiting Verification
                      </span>
                    )}
                  </div>
                  <div style={{ fontSize: 11, color: '#7A8FA6', marginTop: 4 }}>
                    Type: {t.title || t.gtype || 'General Waste Issue'} | Ref: <strong>{t.customTicketId || t.id?.substring(0, 6)}</strong>
                  </div>
                </div>
              );
            })
          )}
        </div>

        {/* RIGHT COLUMN: WORKSPACE DATA MONITOR */}
        <div style={{ flex: 1, background: '#fff', borderRadius: 14, border: '1px solid #DDE3E9', padding: 18, display: 'flex', flexDirection: 'column', gap: 14, overflowY: 'auto', boxShadow: '0 4px 12px rgba(0,0,0,0.02)' }}>
          {selected ? (
            <>
              <div>
                <h4 style={{ margin: '0 0 4px 0', fontSize: 16, color: '#0A1628' }}>Location Telemetry Overlay</h4>
                <p style={{ margin: 0, fontSize: 12, color: '#546E7A' }}>Target Coordinates assigned by Administration System</p>
              </div>

              {/* GIS Map Core Pin View */}
              <LiveMap singlePin={true} singleCoords={{ lat: selected.lat, lng: selected.lng }} height="160px" />
              
              {/* Live Coordinate Display and External Google Maps Redirection Link */}
              {selected.lat && selected.lng && (
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', background: '#F1F5F9', padding: '10px 12px', borderRadius: 8 }}>
                  <div style={{ fontSize: 11, fontFamily: 'monospace', color: '#334155' }}>
                    GPS: {selected.lat.toFixed(5)}, {selected.lng.toFixed(5)}
                  </div>
                  <a 
                    href={`https://www.google.com/maps/search/?api=1&query=${selected.lat},${selected.lng}`} 
                    target="_blank" 
                    rel="noreferrer" 
                    style={{ background: '#1565C0', color: '#fff', padding: '6px 12px', borderRadius: 6, fontSize: 11, fontWeight: 700, textDecoration: 'none', display: 'inline-flex', alignItems: 'center', gap: 4 }}
                  >
                    🗺️ Open In Google Maps
                  </a>
                </div>
              )}

              {/* User Bheji Hui Initial Garbage Image */}
              <div>
                <span style={{ fontSize: 11, fontWeight: 700, color: '#EF4444', display: 'block', marginBottom: 6 }}>
                  ⚠️ USER REPORTED IMAGE (BEFORE CLEANUP):
                </span>
                {(selected.imageUrl || selected.image) ? (
                  <img 
                    src={selected.imageUrl || selected.image} 
                    alt="User evidence" 
                    style={{ width: '100%', height: 150, objectFit: 'cover', borderRadius: 10, border: '1px solid #FCA5A5' }} 
                  />
                ) : (
                  <div style={{ background: '#F8FAFC', padding: 12, borderRadius: 8, fontSize: 12, color: '#64748B', fontStyle: 'italic', textAlign: 'center' }}>
                    No reference picture was uploaded by citizen.
                  </div>
                )}
              </div>

              {/* BOTTOM WORKFLOW WORK ACTION MATRICES */}
              <div style={{ marginTop: 'auto', borderTop: '1px solid #E2E8F0', paddingTop: 14 }}>
                {selected.status === 'ASSIGNED_TO_CLEANER' ? (
                  <div style={{ background: '#F8FAFC', padding: 12, borderRadius: 10, border: '1px solid #E2E8F0' }}>
                    <span style={{ fontSize: 11, fontWeight: 700, color: '#0F172A', display: 'block', marginBottom: 6 }}>
                      📸 SUBMIT WORK EVIDENCE (PASTE PHOTO URL):
                    </span>
                    <input 
                      type="text" 
                      placeholder="https://example.com/cleaned-spot-proof.jpg" 
                      value={proofUrl} 
                      onChange={e => setProofUrl(e.target.value)} 
                      style={{ width: '100%', padding: '10px', fontSize: 12, borderRadius: 6, border: '1px solid #CBD5E1', boxSizing: 'border-box', marginBottom: 10 }} 
                    />
                    <button 
                      onClick={() => handleSendProofToVendor(selected.id)} 
                      style={{ width: '100%', background: '#10B981', color: '#fff', padding: 12, border: 'none', borderRadius: 8, fontWeight: 700, cursor: 'pointer', fontSize: 13 }}
                    >
                      Send Proof to Vendor & Notify Completion
                    </button>
                  </div>
                ) : (
                  <div style={{ background: '#FFF3E0', border: '1px solid #FFE0B2', borderRadius: 10, padding: 14, textAlign: 'center' }}>
                    <div style={{ fontSize: 13, fontWeight: 700, color: '#E65100', marginBottom: 4 }}>
                      ⏳ Verification Processing
                    </div>
                    <div style={{ fontSize: 11, color: '#64748B' }}>
                      Cleaned photo submitted. Waiting for Vendor to inspect visual accuracy and authorize closeout code.
                    </div>
                  </div>
                )}
              </div>
            </>
          ) : (
            <div style={{ margin: 'auto', color: '#7A8FA6', fontSize: 13, textAlign: 'center' }}>
              Select any ticket allocation data card node from the left panel to inspect spatial telemetry parameters.
            </div>
          )}
        </div>

      </div>
    </div>
  );
}
